<?php
require_once __DIR__ . '/billing.php';
require_once __DIR__ . '/payment_gateway.php';
require_once __DIR__ . '/revenue_access_governance.php';
function sf_billing_cancel_subscription_secure(int $id,bool $immediate=false): bool{$pdo=sf_auth_db_required();$userId=sf_current_user_id();if(!$pdo||!$userId||$id<=0)return false;try{$stmt=$pdo->prepare('SELECT * FROM user_subscriptions WHERE id=? AND user_id=? LIMIT 1');$stmt->execute([$id,$userId]);$sub=$stmt->fetch();if(!$sub){sf_auth_flash('error','Subscription not found.');return false;}if(!in_array((string)($sub['status']??''),['active','trialing','past_due'],true)){sf_auth_flash('warning','This subscription is not active.');return false;}$provider=sf_payment_cancel_provider_subscription($sub,$immediate);if(empty($provider['ok'])){sf_auth_flash('error','The payment provider did not confirm cancellation. No local access changes were made.');return false;}$pdo->beginTransaction();if($immediate){$pdo->prepare("UPDATE user_subscriptions SET status='canceled',cancel_at_period_end=0,canceled_at=NOW(),current_period_end=LEAST(COALESCE(current_period_end,NOW()),NOW()),updated_at=NOW() WHERE id=? AND user_id=?")->execute([$id,$userId]);sf_revenue_expire_subscription_grants($pdo,$userId);}else{$pdo->prepare('UPDATE user_subscriptions SET cancel_at_period_end=1,canceled_at=NOW(),updated_at=NOW() WHERE id=? AND user_id=?')->execute([$id,$userId]);}$pdo->commit();sf_auth_flash('success',$immediate?'Subscription canceled immediately.':'Subscription will cancel at the end of the current period.');$recipient=sf_notify_user_recipient($userId);if($recipient)sf_notify_send_template('subscription_canceled',$recipient,['subscription_status'=>$immediate?'canceled':'cancel_at_period_end','period_end'=>$immediate?date('Y-m-d H:i:s'):(string)($sub['current_period_end']??'')],['notification_type'=>'billing','metadata'=>['event'=>'provider_confirmed_cancellation','subscription_id'=>$id,'immediate'=>$immediate],'dispatch'=>true]);return true;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log('Stonefellow secure billing cancellation failed: '.$e->getMessage());sf_auth_flash('error','Cancellation failed.');return false;}}
?>